window.LIVRO_DATA = {
    nome: "Volume 7",
    dados: [
{
    termo: "<span class='numero-ordem'>601.</span> <span class='nome-principal'>Eliabe (Eliab)</span> <span class='subtitulo'>– irmão mais velho de Davi, que Samuel quase ungiu</span>",
    definicao: "<p><strong>Eliabe</strong> foi o filho mais velho de Jessé, irmão de Davi (<span class='versiculo'>1Sm 16:6-7</span>; <span class='versiculo'>17:13,28</span>). Era alto e de boa aparência, mas Deus rejeitou-o porque olha para o coração.</p><ul><li><strong>Ação:</strong> repreendeu Davi quando ele se ofereceu para lutar contra Golias, chamando-o de orgulhoso</li><li><strong>Nome:</strong> significa 'meu Deus é pai'</li><li>Representa a aparência externa que engana, em contraste com a escolha divina do coração</li><li>A rejeição de Eliabe mostra que Deus não se deixa impressionar por critérios humanos</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 16:6-7; 1Sm 17:13,28</span>"
},
{
    termo: "<span class='numero-ordem'>602.</span> <span class='nome-principal'>Abinadabe (Abinadab)</span> <span class='subtitulo'>– segundo irmão de Davi</span>",
    definicao: "<p><strong>Abinadabe</strong> foi o segundo filho de Jessé. Passou diante de Samuel com seus irmãos, mas não foi escolhido (<span class='versiculo'>1Sm 16:8</span>). Também lutou contra os filisteus.</p><ul><li><strong>Nome:</strong> significa 'meu pai é nobre' ou 'pai de generosidade'</li><li>Representa a linhagem de Davi, mas não o escolhido para reinar</li><li>Abinadabe é uma figura periférica na história de Davi</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 16:8; 1Sm 17:13</span>"
},
{
    termo: "<span class='numero-ordem'>603.</span> <span class='nome-principal'>Samá (Shammah)</span> <span class='subtitulo'>– terceiro irmão de Davi</span>",
    definicao: "<p><strong>Samá</strong> foi o terceiro filho de Jessé (<span class='versiculo'>1Sm 16:9</span>). Foi um dos três que passaram por Samuel.</p><ul><li><strong>Nome:</strong> significa 'desolação' ou 'espanto'</li><li>Também mencionado em <span class='versiculo'>1Sm 17:13</span></li><li>Não teve destaque posterior</li><li>Assim como seus irmãos, não foi o escolhido por Deus para ser rei</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 16:9; 1Sm 17:13</span>"
},
{
    termo: "<span class='numero-ordem'>604.</span> <span class='nome-principal'>Amnon</span> <span class='subtitulo'>– filho mais velho de Davi, que violou sua meia-irmã Tamar</span>",
    definicao: "<p><strong>Amnon</strong> foi o primogênito de Davi, nascido de Ainoã, a jezreelita (<span class='versiculo'>2Sm 3:2</span>). Violentou sua meia-irmã <span class='destaque-vermelho'>Tamar</span>, irmã de Absalão. Dois anos depois, Absalão o matou em um banquete (<span class='versiculo'>2Sm 13:1-29</span>).</p><ul><li><strong>Nome:</strong> significa 'fiel' (ironicamente)</li><li>Representa o pecado sexual e a vingança fratricida</li><li>Suas ações tiveram trágicas consequências para a casa de Davi</li><li>A violação de Tamar desencadeou uma série de eventos que levaram à rebelião de Absalão</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 3:2; 2Sm 13:1-29; 1Cr 3:1</span>"
},
{
    termo: "<span class='numero-ordem'>605.</span> <span class='nome-principal'>Quileabe (Daniel)</span> <span class='subtitulo'>– segundo filho de Davi, filho de Abigail (1Cr 3:1)</span>",
    definicao: "<p><strong>Quileabe</strong> foi o segundo filho de Davi, filho de Abigail, a viúva de Nabal (<span class='versiculo'>2Sm 3:3</span>; <span class='versiculo'>1Cr 3:1</span>). Também chamado Daniel.</p><ul><li>Não há registro de seus atos; provavelmente morreu jovem ou sem descendência relevante</li><li><strong>Nome:</strong> significa 'como o pai' ou 'cão do pai'?</li><li>Representa os filhos de Davi que não tiveram destaque na narrativa</li><li>Sua obscuridade contrasta com a fama de seu irmão Absalão</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 3:3; 1Cr 3:1</span>"
},
{
    termo: "<span class='numero-ordem'>606.</span> <span class='nome-principal'>Absalão</span> <span class='subtitulo'>– terceiro filho de Davi, que liderou uma rebelião</span>",
    definicao: "<p><strong>Absalão</strong> foi filho de Davi com Maaca, filha de Talmai, rei de Gesur (<span class='versiculo'>2Sm 3:3</span>). Famoso por sua beleza e <span class='destaque-amarelo'>longos cabelos</span>.</p><ul><li><strong>Ações:</strong> vingou a violação de sua irmã Tamar matando Amnon</li><li>Rebelou-se contra Davi, foi derrotado por Joabe</li><li><strong>Morte:</strong> seus cabelos se enredaram num carvalho, e Joabe o matou (<span class='versiculo'>2Sm 18:9-15</span>)</li><li><strong>Nome:</strong> significa 'pai da paz' (ironicamente)</li><li>Representa a rebeldia filial e as consequências do pecado na família real</li><li>Davi chorou amargamente por sua morte: <span class='destaque-amarelo'>'Meu filho Absalão! Quem dera eu tivesse morrido por ti!'</span></li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 13-18; 1Cr 3:2</span>"
},
{
    termo: "<span class='numero-ordem'>607.</span> <span class='nome-principal'>Sefatias (filho de Davi)</span> <span class='subtitulo'>– quinto filho de Davi (2Sm 3:4; 1Cr 3:3)</span>",
    definicao: "<p><strong>Sefatias</strong> foi o quinto filho de Davi, nascido de Abital (<span class='versiculo'>2Sm 3:4</span>; <span class='versiculo'>1Cr 3:3</span>).</p><ul><li>Nada mais se sabe sobre ele</li><li><strong>Nome:</strong> significa 'Yahweh julga'</li><li>Representa os muitos filhos de Davi que não desempenharam papéis na história</li><li>Sua vida foi ofuscada pelos eventos envolvendo Amnon, Absalão e Adonias</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 3:4; 1Cr 3:3</span>"
},
{
    termo: "<span class='numero-ordem'>608.</span> <span class='nome-principal'>Itreão (Iteão)</span> <span class='subtitulo'>– sexto filho de Davi, filho de Eglá (2Sm 3:5; 1Cr 3:3)</span>",
    definicao: "<p><strong>Itreão</strong> foi o sexto filho de Davi, nascido de Eglá (<span class='versiculo'>2Sm 3:5</span>). Também chamado Iteão em <span class='versiculo'>1Cr 3:3</span>.</p><ul><li>Não há registros de sua vida</li><li><strong>Nome:</strong> significa 'restante' ou 'excelência'</li><li>Representa a descendência menos conhecida de Davi</li><li>Como muitos filhos de Davi, sua história não foi registrada</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 3:5; 1Cr 3:3</span>"
},
{
    termo: "<span class='numero-ordem'>609.</span> <span class='nome-principal'>Tamar (filha de Davi)</span> <span class='subtitulo'>– irmã de Absalão, violada por Amnon</span>",
    definicao: "<p><strong>Tamar</strong> foi filha de Davi com Maaca, irmã de Absalão (<span class='versiculo'>2Sm 13:1</span>). Era bela e virgem. Seu meio-irmão <span class='destaque-vermelho'>Amnon a violentou</span>.</p><ul><li>Absalão a abrigou em sua casa, e depois a vingou matando Amnon</li><li>Tamar ficou desolada, morando na casa de Absalão como viúva</li><li><strong>Nome:</strong> significa 'palmeira'</li><li>Representa a tragédia do abuso sexual e o silêncio das vítimas na corte real</li><li>Sua história é um dos episódios mais sombrios da casa de Davi</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 13:1-22; 1Cr 3:9</span>"
},
{
    termo: "<span class='numero-ordem'>610.</span> <span class='nome-principal'>Maquir (filho de Manassés)</span> <span class='subtitulo'>– diferente do Maquir de Lo-Debar; ancestral de Gileade</span>",
    definicao: "<p><strong>Maquir</strong> foi filho de Manassés, neto de José (<span class='versiculo'>Gn 50:23</span>). Seus descendentes, os maquiritas, receberam a terra de Gileade (<span class='versiculo'>Nm 32:39-40</span>).</p><ul><li><strong>Nome:</strong> significa 'vendido' ou 'comprado'</li><li>Representa a herança das tribos a leste do Jordão</li><li>Maquir é o ancestral da região de Gileade, conhecida por seu bálsamo medicinal</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 50:23; Nm 32:39-40; Js 17:1</span>"
},
{
    termo: "<span class='numero-ordem'>611.</span> <span class='nome-principal'>Abia (filho de Jeroboão I)</span> <span class='subtitulo'>– menino que morreu pela profecia de Aías</span>",
    definicao: "<p><strong>Abia</strong> foi filho de Jeroboão I (rei de Israel). Adoeceu, e Jeroboão enviou sua esposa disfarçada ao profeta Aías. Aías profetizou a morte do menino e a destruição da casa de Jeroboão. Ao entrar em casa, o menino morreu (<span class='versiculo'>1Rs 14:1-18</span>).</p><ul><li><strong>Nome:</strong> significa 'Yahweh é meu pai'</li><li>Representa o juízo divino sobre a idolatria, mesmo afetando os inocentes</li><li>A morte de Abia foi um sinal do julgamento que viria sobre a casa de Jeroboão</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 14:1-18</span>"
},
{
    termo: "<span class='numero-ordem'>612.</span> <span class='nome-principal'>Sisaque (Shishak)</span> <span class='subtitulo'>– faraó egípcio que saqueou Jerusalém no tempo de Roboão</span>",
    definicao: "<p><strong>Sisaque</strong> foi um faraó do Egito (provavelmente Sheshonq I) que invadiu Judá no quinto ano do reinado de Roboão (926 a.C.). Tomou os tesouros do templo e do palácio (<span class='versiculo'>1Rs 14:25-26</span>; <span class='versiculo'>2Cr 12:1-9</span>).</p><ul><li><strong>Nome:</strong> significa 'homem de Rá' ou 'admirador de Rá'</li><li>Representa o juízo divino por meio de nações estrangeiras quando o povo se desvia</li><li>Sisaque é mencionado em inscrições egípcias, confirmando sua historicidade</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 14:25-26; 2Cr 12:1-9</span>"
},
{
    termo: "<span class='numero-ordem'>613.</span> <span class='nome-principal'>Zerá, o etíope (Zerah)</span> <span class='subtitulo'>– comandante etíope derrotado por Asa</span>",
    definicao: "<p><strong>Zerá</strong> foi um comandante do exército etíope que invadiu Judá com um milhão de homens e trezentos carros de guerra (<span class='versiculo'>2Cr 14:9-13</span>).</p><ul><li>Asa clamou ao Senhor, e Deus derrotou os etíopes</li><li><strong>Nome:</strong> significa 'amanhecer' ou 'esplendor'</li><li>Representa a vitória de Deus sobre forças superiores quando há confiança</li><li>A derrota de Zerá foi uma demonstração do poder de Deus em resposta à oração de Asa</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Cr 14:9-13</span>"
},
{
    termo: "<span class='numero-ordem'>614.</span> <span class='nome-principal'>Tiglate-Pileser III (Pul)</span> <span class='subtitulo'>– rei assírio que levou Israel ao cativeiro</span>",
    definicao: "<p><strong>Tiglate-Pileser III</strong> foi rei da Assíria (745-727 a.C.), também chamado Pul (<span class='versiculo'>2Rs 15:19</span>).</p><ul><li>Invadiu Israel nos dias de Menaém, recebeu tributo</li><li>Mais tarde, deportou as tribos de Rúben, Gade e Manassés (<span class='versiculo'>1Cr 5:26</span>)</li><li>É mencionado como instrumento do juízo de Deus</li><li>Representa o poder assírio que destruiu o reino do norte</li><li>Tiglate-Pileser é uma das figuras históricas mais documentadas da Bíblia</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Rs 15:19-20; 2Rs 15:29; 1Cr 5:26</span>"
},
{
    termo: "<span class='numero-ordem'>615.</span> <span class='nome-principal'>Artaxerxes I</span> <span class='subtitulo'>– rei persa que permitiu Neemias reconstruir Jerusalém</span>",
    definicao: "<p><strong>Artaxerxes I</strong> foi rei da Pérsia (465-424 a.C.), filho de Xerxes. Autorizou Neemias a retornar a Jerusalém e reconstruir os muros (<span class='versiculo'>Ne 2:1-8</span>).</p><ul><li><strong>Nome:</strong> significa 'grande governante'</li><li>Representa a benevolência persa para com os judeus no período pós-exílico</li><li>Artaxerxes também é mencionado em <span class='versiculo'>Ne 5:14</span> e <span class='versiculo'>13:6</span></li><li>Sua autorização foi crucial para a restauração de Jerusalém</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ne 2:1-8; Ne 5:14; Ne 13:6</span>"
},
{
    termo: "<span class='numero-ordem'>616.</span> <span class='nome-principal'>Semboque</span> <span class='subtitulo'>– um dos porteiros do templo nos dias de Davi (1Cr 26:7)</span>",
    definicao: "<p><strong>Semboque</strong> foi um descendente de Obede-Edom, um dos porteiros do templo (<span class='versiculo'>1Cr 26:7</span>).</p><ul><li><strong>Nome:</strong> significa 'escapou' ou 'livre'</li><li>Representa os levitas que serviam na segurança do santuário</li><li>Os porteiros eram responsáveis pela guarda das portas do templo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Cr 26:7</span>"
},
{
    termo: "<span class='numero-ordem'>617.</span> <span class='nome-principal'>Eluzai</span> <span class='subtitulo'>– guerreiro de Davi (1Cr 12:5)</span>",
    definicao: "<p><strong>Eluzai</strong> foi um guerreiro benjamita que se uniu a Davi em Ziclague (<span class='versiculo'>1Cr 12:5</span>).</p><ul><li><strong>Nome:</strong> significa 'Deus é minha força'</li><li>Representa os valentes anônimos que arriscaram a vida pelo rei</li><li>Eluzai foi um dos guerreiros que apoiaram Davi antes de ele se tornar rei sobre todo Israel</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Cr 12:5</span>"
},
{
    termo: "<span class='numero-ordem'>618.</span> <span class='nome-principal'>Zinri (guerreiro de Davi)</span> <span class='subtitulo'>– um dos guerreiros de Davi (1Cr 11:44)</span>",
    definicao: "<p><strong>Zinri</strong> foi um dos guerreiros de Davi da tribo de Simeão (<span class='versiculo'>1Cr 4:36-37</span>; <span class='versiculo'>1Cr 11:44</span>).</p><ul><li><strong>Nome:</strong> significa 'meu cântico' ou 'louvor'</li><li>Não confundir com o rei Zinri de Israel (<span class='versiculo'>1Rs 16:9-20</span>)</li><li>Representa os soldados leais a Davi</li><li>A lealdade de Zinri mostra o apoio de todas as tribos a Davi</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Cr 11:44</span>"
},
{
    termo: "<span class='numero-ordem'>619.</span> <span class='nome-principal'>Ismá (Ishma)</span> <span class='subtitulo'>– filho de Joel, da tribo de Simeão (1Cr 4:36)</span>",
    definicao: "<p><strong>Ismá</strong> é mencionado na genealogia de Simeão (<span class='versiculo'>1Cr 4:36</span>).</p><ul><li><strong>Nome:</strong> significa 'desolação' ou 'ouvido'</li><li>É uma figura obscura</li><li>Representa os muitos nomes nos registros genealógicos que nunca receberam narrativa</li><li>Cada nome em 1Crônicas 4 representa uma família que contribuiu para a história de Israel</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Cr 4:36</span>"
},
{
    termo: "<span class='numero-ordem'>620.</span> <span class='nome-principal'>Abia (mulher de Ezequias)</span> <span class='subtitulo'>– mãe de Manassés (2Cr 29:1)</span>",
    definicao: "<p><strong>Abia</strong> (ou Abi) foi filha de Zacarias, esposa do rei Ezequias e mãe do rei Manassés (<span class='versiculo'>2Rs 18:2</span>; <span class='versiculo'>2Cr 29:1</span>).</p><ul><li><strong>Nome:</strong> significa 'meu pai é Yahweh'</li><li>Representa as rainhas-mães de Judá</li><li>Abia foi mãe de um dos reis mais ímpios de Judá (Manassés), que depois se arrependeu</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Rs 18:2; 2Cr 29:1</span>"
},
{
    termo: "<span class='numero-ordem'>621.</span> <span class='nome-principal'>A mãe de Sansão (anônima)</span> <span class='subtitulo'>– tradicionalmente chamada Hazelelponi (apócrifo)</span>",
    definicao: "<p>A <strong>mãe de Sansão</strong> era esposa de Manoá. Era estéril, visitada pelo anjo do Senhor (<span class='versiculo'>Jz 13</span>).</p><ul><li>Anunciou o nascimento do nazireu que libertaria Israel</li><li>Seu nome não é dado na Bíblia</li><li>A tradição a chama de <strong>Hazelelponi</strong> (nome apócrifo)</li><li>Representa a fé das mulheres estéreis que Deus usa para gerar libertadores</li><li>Ela instruiu Manoá sobre como criar o menino</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jz 13:2-25</span>"
},
{
    termo: "<span class='numero-ordem'>622.</span> <span class='nome-principal'>A sogra de Pedro</span> <span class='subtitulo'>– curada por Jesus (Mt 8:14-15)</span>",
    definicao: "<p>A <strong>sogra de Pedro</strong> estava acamada com febre. Jesus a curou, e ela se levantou e passou a servi-lo (<span class='versiculo'>Mt 8:14-15</span>; <span class='versiculo'>Mc 1:29-31</span>; <span class='versiculo'>Lc 4:38-39</span>).</p><ul><li>Seu nome não é dado</li><li>Representa a cura e o serviço imediato após o milagre</li><li>A cura da sogra de Pedro foi uma das primeiras curas registradas no ministério de Jesus</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 8:14-15; Mc 1:29-31; Lc 4:38-39</span>"
},
{
    termo: "<span class='numero-ordem'>623.</span> <span class='nome-principal'>O pai do jovem epiléptico</span> <span class='subtitulo'>– homem que clamou: 'Eu creio; ajuda a minha incredulidade' (Mc 9:24)</span>",
    definicao: "<p>O <strong>pai do jovem epiléptico</strong> levou seu filho possesso a Jesus, após os discípulos não conseguirem curá-lo (<span class='versiculo'>Mc 9:17-29</span>; <span class='versiculo'>Mt 17:14-21</span>; <span class='versiculo'>Lc 9:37-43</span>).</p><ul><li>Disse: 'Se podes fazer alguma coisa, tem compaixão de nós'</li><li>Jesus respondeu: 'Tudo é possível ao que crê'</li><li>O homem exclamou: <span class='destaque-amarelo'>'Eu creio; ajuda a minha incredulidade'</span></li><li>Seu nome não é dado</li><li>Representa a fé imperfeita que clama por ajuda e é respondida</li><li>Sua oração é uma das mais honestas e comoventes do NT</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mc 9:17-29; Mt 17:14-21; Lc 9:37-43</span>"
},
{
    termo: "<span class='numero-ordem'>624.</span> <span class='nome-principal'>O pai do filho pródigo (parábola)</span> <span class='subtitulo'>– personagem simbólico do Pai celestial</span>",
    definicao: "<p>Na parábola de <span class='versiculo'>Lc 15:11-32</span>, o <strong>pai que perdoa o filho pródigo</strong> e celebra seu retorno também sai para chamar o filho mais velho.</p><ul><li>Representa Deus Pai, cheio de misericórdia</li><li>Corre ao encontro do pecador arrependido</li><li>Não é um personagem histórico, mas teológico</li><li>Sua compaixão e graça são o centro da parábola</li><li>O pai restaura a dignidade do filho pródigo com vestes, anel e sandálias</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 15:11-32</span>"
},
{
    termo: "<span class='numero-ordem'>625.</span> <span class='nome-principal'>O administrador desonesto (parábola)</span> <span class='subtitulo'>– Lc 16:1-8</span>",
    definicao: "<p>O <strong>administrador desonesto</strong> é o personagem de parábola que, sabendo que seria despedido, reduziu as dívidas dos devedores para ganhar amigos (<span class='versiculo'>Lc 16:1-8</span>).</p><ul><li>O senhor elogiou sua astúcia</li><li>Jesus usou a parábola para ensinar sobre o uso das riquezas injustas</li><li>Não é histórico, mas didático</li><li>A lição é usar os recursos terrenos para ganhar amigos eternos</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 16:1-8</span>"
},
{
    termo: "<span class='numero-ordem'>626.</span> <span class='nome-principal'>O fariseu Simão</span> <span class='subtitulo'>– que hospedou Jesus e foi confrontado sobre o perdão (Lc 7:36-50)</span>",
    definicao: "<p><strong>Simão</strong> foi um fariseu que convidou Jesus para jantar (<span class='versiculo'>Lc 7:36-50</span>). Uma mulher pecadora ungiu os pés de Jesus com lágrimas e perfume.</p><ul><li>Simão pensou que Jesus não sabia quem ela era</li><li>Jesus contou a parábola dos dois devedores</li><li>Declarou que os muitos pecados dela foram perdoados</li><li><strong>Nome:</strong> significa 'ouvir'</li><li>Representa a arrogância religiosa que não compreende a graça</li><li>Simão foi confrontado com sua falta de hospitalidade e amor</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 7:36-50</span>"
},
{
    termo: "<span class='numero-ordem'>627.</span> <span class='nome-principal'>Herodes Agripa I</span> <span class='subtitulo'>– neto de Herodes, o Grande, que matou Tiago e prendeu Pedro (At 12)</span>",
    definicao: "<p><strong>Herodes Agripa I</strong> (10-44 d.C.) foi neto de Herodes, o Grande. Matou Tiago, filho de Zebedeu, e prendeu Pedro (<span class='versiculo'>At 12:1-4</span>).</p><ul><li><strong>Morte:</strong> morreu comido por vermes (<span class='versiculo'>At 12:20-23</span>) após aceitar adoração como deus</li><li>Representa o poder perseguidor da igreja primitiva, que é julgado por Deus</li><li>O episódio de sua morte é corroborado pelo historiador Josefo</li><li>Agripa I foi o último governante judeu a ter autoridade sobre toda a Palestina</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 12:1-23</span>"
},
{
    termo: "<span class='numero-ordem'>628.</span> <span class='nome-principal'>Herodes Agripa II</span> <span class='subtitulo'>– filho de Agripa I, diante de quem Paulo se defendeu (At 25-26)</span>",
    definicao: "<p><strong>Herodes Agripa II</strong> foi o último rei da dinastia herodiana. Ouviu a defesa de Paulo em Cesareia, junto com sua irmã <span class='destaque-amarelo'>Berenice</span> (<span class='versiculo'>At 25:13-26:32</span>).</p><ul><li>Disse a Paulo: <span class='destaque-amarelo'>'Por pouco me queres persuadir a fazer-me cristão'</span> (<span class='versiculo'>At 26:28</span>)</li><li>Não se converteu</li><li>Representa os governantes que ouvem o evangelho mas não creem</li><li>Agripa II foi o último da dinastia herodiana</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 25:13-26:32</span>"
},
{
    termo: "<span class='numero-ordem'>629.</span> <span class='nome-principal'>Drusila</span> <span class='subtitulo'>– esposa de Félix, ouviu Paulo (At 24:24)</span>",
    definicao: "<p><strong>Drusila</strong> era filha de Herodes Agripa I, esposa do governador Félix (<span class='versiculo'>At 24:24</span>).</p><ul><li>Era judia e ouviu Paulo falar sobre justiça e domínio próprio</li><li><strong>Nome:</strong> significa 'regada pelo orvalho'</li><li>Representa a elite judaica que ouve o evangelho mas não se converte</li><li>Drusila estava presente quando Paulo pregou a Félix</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 24:24</span>"
},
{
    termo: "<span class='numero-ordem'>630.</span> <span class='nome-principal'>Berenice</span> <span class='subtitulo'>– irmã de Herodes Agripa II (At 25:13,23; 26:30)</span>",
    definicao: "<p><strong>Berenice</strong> era filha de Herodes Agripa I, irmã de Agripa II. Esteve presente na defesa de Paulo em Cesareia (<span class='versiculo'>At 25:13,23</span>; <span class='versiculo'>26:30</span>).</p><ul><li>Era conhecida por seus relacionamentos controversos (viveu com seu irmão Agripa II)</li><li><strong>Nome:</strong> significa 'portadora da vitória'</li><li>Representa a realeza herodiana que testemunhou o evangelho mas não creu</li><li>Berenice e Agripa II ouviram a defesa de Paulo com interesse</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 25:13,23; At 26:30</span>"
},
{
    termo: "<span class='numero-ordem'>631.</span> <span class='nome-principal'>Públio</span> <span class='subtitulo'>– chefe da ilha de Malta (At 28:7-10)</span>",
    definicao: "<p><strong>Públio</strong> foi o governador romano de Malta (chamado 'principal da ilha'). Recebeu Paulo e seus companheiros após o naufrágio (<span class='versiculo'>At 28:7-10</span>).</p><ul><li>Seu pai estava doente de febre e disenteria; Paulo o curou</li><li><strong>Nome:</strong> significa 'público' ou 'do povo'</li><li>Representa a hospitalidade e o reconhecimento do poder de Deus</li><li>Públio hospedou Paulo por três dias com grande hospitalidade</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 28:7-10</span>"
},
{
    termo: "<span class='numero-ordem'>632.</span> <span class='nome-principal'>O pai de Públio</span> <span class='subtitulo'>– anônimo, curado por Paulo em Malta</span>",
    definicao: "<p>O <strong>pai de Públio</strong> estava doente de febre e disenteria. Paulo orou, impôs as mãos e o curou (<span class='versiculo'>At 28:8-9</span>).</p><ul><li>Seu nome não é dado</li><li>Este milagre levou outros doentes da ilha a virem a Paulo para cura</li><li>Representa a cura física como porta de entrada para o evangelho</li><li>A cura do pai de Públio abriu o caminho para a evangelização de Malta</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 28:8-9</span>"
},
{
    termo: "<span class='numero-ordem'>633.</span> <span class='nome-principal'>Gálio</span> <span class='subtitulo'>– procônsul da Acaia (At 18:12-17)</span>",
    definicao: "<p><strong>Gálio</strong>, irmão do filósofo Sêneca, foi procônsul da Acaia (Corinto) (<span class='versiculo'>At 18:12-17</span>).</p><ul><li>Os judeus acusaram Paulo, mas Gálio recusou julgar o caso</li><li>Disse que se tratava de questões de palavras e da lei judaica</li><li>Expulsou os acusadores</li><li><strong>Nome:</strong> significa 'leite' (latim)</li><li>Representa a atitude romana de neutralidade em relação aos conflitos religiosos, que protegeu Paulo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 18:12-17</span>"
},
{
    termo: "<span class='numero-ordem'>634.</span> <span class='nome-principal'>Crispo</span> <span class='subtitulo'>– chefe da sinagoga de Corinto convertido (At 18:8; 1Co 1:14)</span>",
    definicao: "<p><strong>Crispo</strong> era o chefe da sinagoga de Corinto. Creu no Senhor com toda a sua casa e foi batizado por Paulo (<span class='versiculo'>At 18:8</span>; <span class='versiculo'>1Co 1:14</span>).</p><ul><li><strong>Nome:</strong> significa 'enrolado' ou 'crespo'</li><li>Representa a conversão de líderes religiosos judeus ao cristianismo</li><li>Sua conversão foi um marco na igreja de Corinto</li><li>Crispo foi um dos poucos que Paulo batizou pessoalmente</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 18:8; 1Co 1:14</span>"
},
{
    termo: "<span class='numero-ordem'>635.</span> <span class='nome-principal'>Sóstenes</span> <span class='subtitulo'>– chefe da sinagoga em Corinto, espancado diante de Gálio (At 18:17)</span>",
    definicao: "<p><strong>Sóstenes</strong> era o chefe da sinagoga após Crispo (ou um líder judeu). Os gregos o agarraram e espancaram diante do tribunal de Gálio, que não se importou (<span class='versiculo'>At 18:17</span>).</p><ul><li>É possivelmente o mesmo Sóstenes mencionado em <span class='versiculo'>1Co 1:1</span> como 'irmão' e coautor da carta</li><li><strong>Nome:</strong> significa 'forte salvador'</li><li>Representa a perseguição que os líderes judeus podiam sofrer dos próprios gentios</li><li>O espancamento de Sóstenes mostra a tensão entre judeus e gregos em Corinto</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 18:17; 1Co 1:1</span>"
},
{
    termo: "<span class='numero-ordem'>636.</span> <span class='nome-principal'>Aimeleque</span> <span class='subtitulo'>– pai de Abiatar, sumo sacerdote de Nobe (1Sm 21:1-9; 22:9-23)</span>",
    definicao: "<p><strong>Aimeleque</strong> foi sumo sacerdote em Nobe, descendente de Eli. Deu a Davi os pães da proposição e a espada de Golias (<span class='versiculo'>1Sm 21:1-9</span>).</p><ul><li>Saul, por meio de Doegue, o edomita, matou Aimeleque e 85 sacerdotes de Nobe (<span class='versiculo'>1Sm 22:9-23</span>)</li><li><strong>Nome:</strong> significa 'meu irmão é rei' ou 'irmão do rei'</li><li>Representa o martírio sacerdotal por ajudar a Davi</li><li>Aimeleque foi um dos primeiros mártires da história de Israel</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 21:1-9; 1Sm 22:9-23; Sl 52</span>"
},
{
    termo: "<span class='numero-ordem'>637.</span> <span class='nome-principal'>Joiaquim (sumo sacerdote)</span> <span class='subtitulo'>– sucessor de Josué no pós-exílio (Ne 12:10,12,26)</span>",
    definicao: "<p><strong>Joiaquim</strong> foi sumo sacerdote depois de Josué (Jesua) no período pós-exílico (<span class='versiculo'>Ne 12:10,12,26</span>).</p><ul><li><strong>Nome:</strong> significa 'Yahweh estabelece'</li><li>É uma figura na linhagem sacerdotal que liderou o templo reconstruído</li><li>Joiaquim foi o sumo sacerdote durante o ministério de Neemias</li><li>Representa a continuidade do sacerdócio após o exílio</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ne 12:10,12,26</span>"
},
{
    termo: "<span class='numero-ordem'>638.</span> <span class='nome-principal'>Eliaquim (filho de Hilquias)</span> <span class='subtitulo'>– mordomo do rei Ezequias (2Rs 18:18; Is 36:3)</span>",
    definicao: "<p><strong>Eliaquim</strong>, filho de Hilquias, era o mordomo (ou governador) do palácio de Ezequias. Representou o rei nas negociações com Rabsaqué (<span class='versiculo'>2Rs 18:18</span>; <span class='versiculo'>Is 36:3</span>).</p><ul><li>Deus prometeu que ele seria um <span class='destaque-amarelo'>'prego fixado em lugar seguro'</span> (<span class='versiculo'>Is 22:20-25</span>)</li><li><strong>Nome:</strong> significa 'Deus estabelecerá'</li><li>É um tipo de Cristo (<span class='versiculo'>Ap 3:7</span> – a chave de Davi)</li><li>Eliaquim foi um administrador fiel durante a crise assíria</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Rs 18:18; 2Rs 19:2; Is 22:20-25; Is 36:3; Is 37:2</span>"
},
{
    termo: "<span class='numero-ordem'>639.</span> <span class='nome-principal'>Sebna</span> <span class='subtitulo'>– escriba (ou mordomo) de Ezequias, deposto por orgulho (Is 22:15-19)</span>",
    definicao: "<p><strong>Sebna</strong> era o mordomo (ou secretário) de Ezequias, mas foi deposto por sua arrogância e por cavar um túmulo para si (<span class='versiculo'>Is 22:15-19</span>).</p><ul><li>Isaías profetizou que ele seria deportado e morreria em terra estrangeira</li><li><strong>Nome:</strong> significa 'juventude' ou 'crescimento'</li><li>Representa o orgulho que leva à queda</li><li>Sebna foi substituído por Eliaquim, que era mais fiel</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Is 22:15-19; 2Rs 18:18 (mencionado como escriba)</span>"
},
{
    termo: "<span class='numero-ordem'>640.</span> <span class='nome-principal'>Rabsaqué</span> <span class='subtitulo'>– comandante assírio que blasfemou contra Deus (2Rs 18:17-37)</span>",
    definicao: "<p><strong>Rabsaqué</strong> era um oficial assírio (título, não nome próprio) enviado por Senaqueribe para exigir a rendição de Jerusalém (<span class='versiculo'>2Rs 18:17-37</span>).</p><ul><li>Falou em hebraico para o povo, zombando de Ezequias e de Deus</li><li>Seu discurso foi respondido por Eliaquim, Sebna e Joá</li><li><strong>Nome:</strong> significa 'chefe dos príncipes' ou 'grande copeiro'</li><li>Representa a arrogância dos inimigos de Deus, que serão humilhados</li><li>O discurso de Rabsaqué é um dos exemplos de blasfêmia mais vívidos da Bíblia</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Rs 18:17-37; 2Cr 32:9-19; Is 36:2-22</span>"
},
{
    termo: "<span class='numero-ordem'>641.</span> <span class='nome-principal'>Joá, filho de Asafe</span> <span class='subtitulo'>– cronista do rei Ezequias (2Rs 18:18; Is 36:3)</span>",
    definicao: "<p><strong>Joá</strong>, filho de Asafe, era o cronista (historiador) do rei Ezequias. Participou da delegação que encontrou Rabsaqué (<span class='versiculo'>2Rs 18:18,37</span>; <span class='versiculo'>Is 36:3,22</span>).</p><ul><li><strong>Nome:</strong> significa 'Yahweh é irmão'</li><li>Representa os funcionários fiéis que serviram ao rei durante a crise assíria</li><li>Joá também esteve presente na oração de Ezequias pela libertação</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Rs 18:18,37; 2Rs 19:5; Is 36:3,22; Is 37:5</span>"
},
{
    termo: "<span class='numero-ordem'>642.</span> <span class='nome-principal'>Jonadabe, filho de Recabe</span> <span class='subtitulo'>– líder dos recabitas (2Rs 10:15-16; Jr 35:6-10)</span>",
    definicao: "<p><strong>Jonadabe</strong>, filho de Recabe, foi um líder que ordenou a seus descendentes que não bebessem vinho, não construíssem casas e vivessem em tendas (<span class='versiculo'>Jr 35:6-10</span>).</p><ul><li>Apoiou Jeú na destruição da casa de Acabe (<span class='versiculo'>2Rs 10:15-16</span>)</li><li>Seus descendentes, os recabitas, foram elogiados por Deus por sua obediência</li><li><strong>Nome:</strong> significa 'Yahweh é nobre'</li><li>Representa a fidelidade a votos e tradições piedosas</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Rs 10:15-16; Jr 35:1-19</span>"
},
{
    termo: "<span class='numero-ordem'>643.</span> <span class='nome-principal'>Os recabitas</span> <span class='subtitulo'>– exemplo de obediência (Jr 35)</span>",
    definicao: "<p>Os <strong>recabitas</strong> foram um grupo familiar que obedeceu rigorosamente às ordens de Jonadabe, recusando vinho e casas fixas (<span class='versiculo'>Jr 35</span>).</p><ul><li>Deus os usou como exemplo de fidelidade em contraste com Judá, que desobedecia à aliança</li><li>Representam a importância da disciplina e da transmissão da fé através das gerações</li><li>Jeremias os levou ao templo e lhes ofereceu vinho; eles recusaram</li><li>Deus declarou que os recabitas sempre teriam um descendente diante dele</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jr 35:1-19</span>"
},
{
    termo: "<span class='numero-ordem'>644.</span> <span class='nome-principal'>Ebed-Meleque</span> <span class='subtitulo'>– eunuco etíope que salvou Jeremias da cisterna (Jr 38:7-13; 39:15-18)</span>",
    definicao: "<p><strong>Ebed-Meleque</strong>, eunuco etíope da corte do rei Zedequias, intercedeu por Jeremias quando os príncipes o jogaram na cisterna (<span class='versiculo'>Jr 38:7-13</span>).</p><ul><li>Com a permissão do rei, tirou Jeremias da lama, usando panos velhos e cordas</li><li>Deus prometeu livrá-lo do juízo (<span class='versiculo'>Jr 39:15-18</span>)</li><li><strong>Nome:</strong> significa 'servo do rei'</li><li>Representa a coragem de estrangeiros que temem a Deus mais do que os próprios israelitas</li><li>Ebed-Meleque é um exemplo de justiça e compaixão em meio à corrupção</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jr 38:7-13; Jr 39:15-18</span>"
},
{
    termo: "<span class='numero-ordem'>645.</span> <span class='nome-principal'>Festo (Pórcio Festo)</span> <span class='subtitulo'>– governador romano da Judeia que sucedeu Félix (At 24:27; 25-26)</span>",
    definicao: "<p><strong>Pórcio Festo</strong> foi o governador romano da Judeia que sucedeu Félix (<span class='versiculo'>At 24:27</span>). Ouviu a defesa de Paulo e o enviou a Roma para apelar a César (<span class='versiculo'>At 25-26</span>).</p><ul><li><strong>Nome:</strong> significa 'festivo' (latim)</li><li>Representa a imparcialidade da justiça romana, embora não tenha compreendido o cristianismo</li><li>Festo disse a Paulo: 'Estás louco, Paulo! As muitas letras te fazem delirar' (<span class='versiculo'>At 26:24</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 24:27; At 25:1-26:32</span>"
},
{
    termo: "<span class='numero-ordem'>646.</span> <span class='nome-principal'>Trófimo</span> <span class='subtitulo'>– companheiro de Paulo, de Éfeso (At 20:4; 21:29; 2Tm 4:20)</span>",
    definicao: "<p><strong>Trófimo</strong>, natural de Éfeso, acompanhou Paulo a Jerusalém e foi uma das causas de sua prisão (<span class='versiculo'>At 21:29</span>).</p><ul><li>Paulo o deixou doente em Mileto (<span class='versiculo'>2Tm 4:20</span>)</li><li><strong>Nome:</strong> significa 'alimentado' ou 'nutrido'</li><li>Representa os companheiros leais que sofreram com o apóstolo</li><li>Trófimo foi acusado pelos judeus de levar gentios ao templo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 20:4; At 21:29; 2Tm 4:20</span>"
},
{
    termo: "<span class='numero-ordem'>647.</span> <span class='nome-principal'>Himeneu</span> <span class='subtitulo'>– herege que ensinava que a ressurreição já havia ocorrido (1Tm 1:20; 2Tm 2:17-18)</span>",
    definicao: "<p><strong>Himeneu</strong> foi um herege que ensinava que a ressurreição já havia ocorrido, subvertendo a fé de alguns (<span class='versiculo'>2Tm 2:17-18</span>).</p><ul><li>Paulo o entregou a Satanás para aprender a não blasfemar (<span class='versiculo'>1Tm 1:20</span>)</li><li><strong>Nome:</strong> significa 'pertencente a Himeneu' (deus do casamento)</li><li>Representa falsos mestres que negam a ressurreição futura</li><li>Juntamente com Fileto, disseminou heresias na igreja primitiva</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Tm 1:20; 2Tm 2:17-18</span>"
},
{
    termo: "<span class='numero-ordem'>648.</span> <span class='nome-principal'>Fileto</span> <span class='subtitulo'>– companheiro de Himeneu na heresia da ressurreição passada (2Tm 2:17)</span>",
    definicao: "<p><strong>Fileto</strong>, juntamente com Himeneu, ensinava que a ressurreição já havia acontecido, desviando muitos da fé (<span class='versiculo'>2Tm 2:17-18</span>).</p><ul><li><strong>Nome:</strong> significa 'amado' ou 'querido'</li><li>Representa a propagação de ensinos falsos dentro da igreja</li><li>Paulo adverte Timóteo a evitar tais ensinos</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Tm 2:17-18</span>"
},
{
    termo: "<span class='numero-ordem'>649.</span> <span class='nome-principal'>Alexandre, o latoeiro</span> <span class='subtitulo'>– que fez muito mal a Paulo (2Tm 4:14-15)</span>",
    definicao: "<p><strong>Alexandre, o latoeiro</strong> (ourives ou ferreiro) causou muitos danos a Paulo. O apóstolo adverte Timóteo a também se precaver dele (<span class='versiculo'>2Tm 4:14-15</span>).</p><ul><li>Pode ser o mesmo Alexandre mencionado em <span class='versiculo'>1Tm 1:20</span> (entregue a Satanás)</li><li><strong>Nome:</strong> significa 'defensor dos homens'</li><li>Representa opositores do evangelho que surgem até entre os que professam a fé</li><li>Paulo diz que o Senhor o recompensará segundo suas obras</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Tm 4:14-15; 1Tm 1:20 (possível)</span>"
},
{
    termo: "<span class='numero-ordem'>650.</span> <span class='nome-principal'>Os filhos de Ceva</span> <span class='subtitulo'>– exorcistas judeus derrotados por um demônio (At 19:13-16)</span>",
    definicao: "<p>Os <strong>filhos de Ceva</strong> eram exorcistas judeus itinerantes que tentaram expulsar demônios usando o nome de Jesus que Paulo pregava (<span class='versiculo'>At 19:13-16</span>).</p><ul><li>O demônio respondeu: <span class='destaque-vermelho'>'Conheço a Jesus e sei quem é Paulo; mas vós, quem sois?'</span></li><li>O possesso os feriu, e eles fugiram nus</li><li>Ceva significa 'desejado' ou 'pedra'</li><li>Representa o perigo de usar o nome de Jesus sem ter relacionamento com ele</li><li>Este evento causou grande temor em Éfeso</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 19:13-16</span>"
},
{
    termo: "<span class='numero-ordem'>651.</span> <span class='nome-principal'>Eutico</span> <span class='subtitulo'>– o coroinha que caiu da janela (At 20:9-12)</span>",
    definicao: "<p><strong>Eutico</strong> era um jovem de Trôade que sentou-se na janela durante a longa pregação de Paulo até a meia-noite. Adormeceu e caiu do terceiro andar, sendo recolhido morto (<span class='versiculo'>At 20:9-12</span>).</p><ul><li>Paulo o abraçou e ressuscitou, dizendo: <span class='destaque-amarelo'>'Não vos perturbeis, que a sua alma está nele'</span></li><li><strong>Nome:</strong> significa 'afortunado' ou 'sortudo'</li><li>Representa o cuidado de Deus e o poder da ressurreição</li><li>A ressurreição de Eutico confortou a igreja de Trôade</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 20:9-12</span>"
},
{
    termo: "<span class='numero-ordem'>652.</span> <span class='nome-principal'>As quatro filhas de Filipe, o evangelista</span> <span class='subtitulo'>– profetisas (At 21:8-9)</span>",
    definicao: "<p>Filipe, o evangelista (um dos sete diáconos), tinha <strong>quatro filhas virgens que profetizavam</strong> (<span class='versiculo'>At 21:8-9</span>).</p><ul><li>Seus nomes não são dados</li><li>Representam as mulheres no ministério profético da igreja primitiva</li><li>A tradição as chama de Hermione, etc., mas não é bíblico</li><li>As filhas de Filipe são um exemplo do dom profético exercido por mulheres</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 21:8-9</span>"
},
{
    termo: "<span class='numero-ordem'>653.</span> <span class='nome-principal'>Alexandre (filho de Simão cireneu)</span> <span class='subtitulo'>– mencionado em Marcos 15:21</span>",
    definicao: "<p><strong>Alexandre</strong>, filho de Simão cireneu, é mencionado em <span class='versiculo'>Mc 15:21</span> para identificação, indicando que ele e seu irmão Rufo eram conhecidos na igreja de Marcos.</p><ul><li><strong>Nome:</strong> significa 'defensor'</li><li>Representa a segunda geração de cristãos na igreja primitiva</li><li>Alexandre pode ser o mesmo mencionado em <span class='versiculo'>2Tm 4:14</span>? Não há certeza</li><li>Rufo também é mencionado em <span class='versiculo'>Rm 16:13</span></li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mc 15:21</span>"
},
{
    termo: "<span class='numero-ordem'>654.</span> <span class='nome-principal'>Neco (Faraó Neco)</span> <span class='subtitulo'>– faraó egípcio que matou o rei Josias em Megido (2Rs 23:29; 2Cr 35:20-24)</span>",
    definicao: "<p><strong>Faraó Neco II</strong> (610-595 a.C.) subiu contra a Assíria, e o rei Josias foi enfrentá-lo em Megido, sendo mortalmente ferido (<span class='versiculo'>2Rs 23:29</span>; <span class='versiculo'>2Cr 35:20-24</span>).</p><ul><li>Neco também depôs Jeoacaz e impôs tributo a Judá</li><li><strong>Nome:</strong> significa 'bom' ou 'aquele que pertence ao deus Neith'</li><li>Representa o poder egípcio que interferiu na política judaica</li><li>A morte de Josias em Megido foi uma tragédia nacional</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Rs 23:29-35; 2Cr 35:20-24; 2Cr 36:1-4</span>"
},
{
    termo: "<span class='numero-ordem'>655.</span> <span class='nome-principal'>Joanã (filho de Josias)</span> <span class='subtitulo'>– primogênito de Josias, que não reinou (1Cr 3:15)</span>",
    definicao: "<p><strong>Joanã</strong> foi o primogênito do rei Josias, mencionado em <span class='versiculo'>1Cr 3:15</span>. Seus irmãos reinaram: Jeoaquim, Zedequias e Jeoacaz.</p><ul><li><strong>Nome:</strong> significa 'Yahweh é gracioso'</li><li>Representa os herdeiros não coroados</li><li>Joanã não teve destaque político</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Cr 3:15</span>"
},
{
    termo: "<span class='numero-ordem'>656.</span> <span class='nome-principal'>Maaseias (filho de Acaz)</span> <span class='subtitulo'>– assassinado por Zicri (2Cr 28:7)</span>",
    definicao: "<p><strong>Maaseias</strong> foi filho do rei Acaz, morto por Zicri durante a invasão de Peca, rei de Israel (<span class='versiculo'>2Cr 28:7</span>).</p><ul><li><strong>Nome:</strong> significa 'obra de Yahweh'</li><li>Representa a tragédia da guerra civil entre Israel e Judá</li><li>Sua morte foi parte da derrota de Judá nas mãos de Peca</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Cr 28:7</span>"
},
{
    termo: "<span class='numero-ordem'>657.</span> <span class='nome-principal'>Os filhos de Josafá</span> <span class='subtitulo'>– mortos por seu irmão Jeorão (2Cr 21:2-4)</span>",
    definicao: "<p>Josafá teve vários filhos: <strong>Azarias, Jeiel, Zacarias, Azariau, Micael e Sefatias</strong>. Todos foram mortos por seu irmão Jeorão após ele se tornar rei (<span class='versiculo'>2Cr 21:2-4</span>).</p><ul><li>Azarias significa 'Yahweh ajudou'</li><li>Representam a tragédia de irmãos mortos pela ambição</li><li>Jeorão matou seus irmãos para consolidar o poder</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Cr 21:2-4</span>"
},
{
    termo: "<span class='numero-ordem'>658.</span> <span class='nome-principal'>Os filhos de Davi nascidos em Jerusalém</span> <span class='subtitulo'>– 1Cr 3:5-9</span>",
    definicao: "<p>Além dos já listados, Davi teve filhos com Bate-Seba: <strong>Samua, Sobabe, Natã</strong> (ancestral de Jesus por Maria) e <strong>Salomão</strong>.</p><ul><li>Também com outras esposas: <strong>Ibar, Elisaúa, Elifelete, Nogá, Nefegue, Jafia, Elisama, Eliada e Elifelete</strong></li><li>Natã é importante na genealogia de Lucas (<span class='versiculo'>Lc 3:31</span>)</li><li>Esses nomes representam a numerosa prole de Davi, a maioria sem história</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Cr 3:5-9; 2Sm 5:14-16</span>"
},
{
    termo: "<span class='numero-ordem'>659.</span> <span class='nome-principal'>Natã (filho de Davi)</span> <span class='subtitulo'>– ancestral de Jesus por parte de Maria (Lc 3:31)</span>",
    definicao: "<p><strong>Natã</strong>, filho de Davi com Bate-Seba, não reinou, mas sua linhagem continuou através de Maria, mãe de Jesus (<span class='versiculo'>Lc 3:31</span>).</p><ul><li><strong>Nome:</strong> significa 'ele deu'</li><li>Representa a linhagem real não coroada que ainda produziu o Messias</li><li>Natã é mencionado em <span class='versiculo'>2Sm 5:14</span>; <span class='versiculo'>1Cr 3:5</span>; <span class='versiculo'>Zc 12:12</span></li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 5:14; 1Cr 3:5; Zc 12:12; Lc 3:31</span>"
},
{
    termo: "<span class='numero-ordem'>660.</span> <span class='nome-principal'>Tafate</span> <span class='subtitulo'>– filha de Salomão, casada com o filho de Abinadabe (1Rs 4:11)</span>",
    definicao: "<p><strong>Tafate</strong> foi uma das filhas de Salomão, dada em casamento a Ben-Abinadabe, um dos seus comissários (<span class='versiculo'>1Rs 4:11</span>).</p><ul><li><strong>Nome:</strong> significa 'gota' ou 'ornamento'</li><li>Representa as alianças matrimoniais da corte de Salomão</li><li>As filhas de Salomão eram usadas para consolidar alianças políticas</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 4:11</span>"
},
{
    termo: "<span class='numero-ordem'>661.</span> <span class='nome-principal'>Basemate</span> <span class='subtitulo'>– outra filha de Salomão, casada com Aimaás (1Rs 4:15)</span>",
    definicao: "<p><strong>Basemate</strong> foi outra filha de Salomão, casada com Aimaás, que era governador de Naftali (<span class='versiculo'>1Rs 4:15</span>).</p><ul><li><strong>Nome:</strong> significa 'perfume' ou 'fragrância'</li><li>Representa as filhas do rei usadas para consolidar o reino</li><li>Basemate é um exemplo de como a diplomacia era mantida por casamentos</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 4:15</span>"
},
{
    termo: "<span class='numero-ordem'>662.</span> <span class='nome-principal'>A filha de Absalão (Tamar)</span> <span class='subtitulo'>– mencionada em 2Sm 14:27</span>",
    definicao: "<p>Absalão teve três filhos (não nomeados) e uma <strong>filha chamada Tamar</strong> (como sua irmã), que se tornou bela (<span class='versiculo'>2Sm 14:27</span>).</p><ul><li>Os filhos morreram jovens, e Absalão erigiu uma coluna para perpetuar seu nome (<span class='versiculo'>2Sm 18:18</span>)</li><li><strong>Nome:</strong> significa 'palmeira'</li><li>Representa a linhagem extinta de um rebelde</li><li>Tamar é a única descendente de Absalão mencionada</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 14:27; 2Sm 18:18</span>"
},
{
    termo: "<span class='numero-ordem'>663.</span> <span class='nome-principal'>Ada e Zilá</span> <span class='subtitulo'>– esposas de Lameque, o cainita (Gn 4:19-24)</span>",
    definicao: "<p><strong>Ada e Zilá</strong> foram as duas esposas de Lameque, descendente de Caim (<span class='versiculo'>Gn 4:19-24</span>).</p><ul><li>Ada deu à luz <strong>Jabal</strong> (pastor) e <strong>Jubal</strong> (músico)</li><li>Zilá deu à luz <strong>Tubalcaim</strong> (metalúrgico) e <strong>Naamá</strong></li><li>Ada significa 'ornamento'; Zilá significa 'sombra'</li><li>Representam as primeiras poligamias e o desenvolvimento da cultura</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 4:19-24</span>"
},
{
    termo: "<span class='numero-ordem'>664.</span> <span class='nome-principal'>Naamá (irmã de Tubalcaim)</span> <span class='subtitulo'>– filha de Zilá (Gn 4:22)</span>",
    definicao: "<p><strong>Naamá</strong> foi filha de Lameque e Zilá, irmã de Tubalcaim. É a primeira mulher nomeada na linha de Caim (<span class='versiculo'>Gn 4:22</span>).</p><ul><li><strong>Nome:</strong> significa 'agradável'</li><li>Representa a descendência de Caim que desenvolveu a civilização, mas sem Deus</li><li>Naamá é um dos nomes femininos mais antigos na Bíblia</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 4:22</span>"
},
{
    termo: "<span class='numero-ordem'>665.</span> <span class='nome-principal'>Os filhos de Sem</span> <span class='subtitulo'>– Elão, Assur, Arfaxade, Lud, Arã (Gn 10:21-31)</span>",
    definicao: "<p>Os <strong>filhos de Sem</strong> foram: <strong>Elão</strong> (elamitas), <strong>Assur</strong> (assírios), <strong>Arfaxade</strong> (ancestral de Abraão), <strong>Lud</strong> (lídios) e <strong>Arã</strong> (arameus) (<span class='versiculo'>Gn 10:21-31</span>).</p><ul><li>Arfaxade é o ancestral da linhagem messiânica</li><li>Elão deu nome aos elamitas; Assur aos assírios</li><li>Representam a expansão dos descendentes de Noé</li><li>A genealogia de Sem é fundamental para a história da redenção</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 10:21-31</span>"
},
{
    termo: "<span class='numero-ordem'>666.</span> <span class='nome-principal'>Os filhos de Jafé</span> <span class='subtitulo'>– Gomer, Magogue, Madai, Javã, Tubal, Meseque, Tiras (Gn 10:2-5)</span>",
    definicao: "<p>Os <strong>filhos de Jafé</strong> foram: <strong>Gomer</strong> (cimérios), <strong>Magogue</strong>, <strong>Madai</strong> (medos), <strong>Javã</strong> (gregos), <strong>Tubal</strong>, <strong>Meseque</strong> e <strong>Tiras</strong> (<span class='versiculo'>Gn 10:2-5</span>).</p><ul><li>Deram origem aos povos indo-europeus</li><li>Javã é ancestral dos gregos; de Javã vieram Elisá, Társis, Quitim e Rodanim</li><li>Não são personagens ativos, apenas eponímos</li><li>Representam a expansão dos descendentes de Noé para o Ocidente</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 10:2-5</span>"
},
{
    termo: "<span class='numero-ordem'>667.</span> <span class='nome-principal'>Os filhos de Cam</span> <span class='subtitulo'>– Cuxe, Mizraim, Pute, Canaã (Gn 10:6-20)</span>",
    definicao: "<p>Os <strong>filhos de Cam</strong> foram: <strong>Cuxe</strong> (Etiópia), <strong>Mizraim</strong> (Egito), <strong>Pute</strong> (Líbia) e <strong>Canaã</strong> (<span class='versiculo'>Gn 10:6-20</span>).</p><ul><li>Cuxe gerou Ninrode (17)</li><li>Mizraim gerou os filisteus (originários de Caftorim)</li><li>Canaã gerou os cananeus</li><li>A Tabela das Nações (Gn 10) é fundamental para a etnografia bíblica</li><li>Os descendentes de Cam incluem as nações da África e do Oriente Médio</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 10:6-20</span>"
},
{
    termo: "<span class='numero-ordem'>668.</span> <span class='nome-principal'>A Tabela das Nações (Gn 10)</span> <span class='subtitulo'>– genealogia pós-diluviana dos descendentes de Noé</span>",
    definicao: "<p>A <strong>Tabela das Nações</strong> em <span class='versiculo'>Gn 10</span> lista os descendentes de Noé (Sem, Cam e Jafé) e a origem das nações conhecidas por Israel.</p><ul><li><strong>Propósito:</strong> mostra a unidade da humanidade e a dispersão dos povos</li><li>É o fundamento da etnografia bíblica</li><li>De Sem vieram os hebreus e os povos do Oriente Médio</li><li>De Jafé vieram os indo-europeus</li><li>De Cam vieram os povos da África e Canaã</li><li>A tabela é uma ponte entre a história primordial e a chamada de Abraão</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 10:1-32; 1Cr 1:1-23</span>"
},
{
    termo: "<span class='numero-ordem'>669.</span> <span class='nome-principal'>A criação do mundo em sete dias – Gênesis 1-2</span> <span class='subtitulo'>– fundamento da teologia bíblica</span>",
    definicao: "<p>Deus criou os céus e a terra em <strong>seis dias</strong> e descansou no <strong>sétimo dia</strong> (<span class='versiculo'>Gn 1:1-2:3</span>).</p><ul><li><strong>Dia 1:</strong> luz</li><li><strong>Dia 2:</strong> firmamento</li><li><strong>Dia 3:</strong> terra seca e vegetação</li><li><strong>Dia 4:</strong> sóis, lua e estrelas</li><li><strong>Dia 5:</strong> peixes e aves</li><li><strong>Dia 6:</strong> animais terrestres e o homem</li><li><strong>Dia 7:</strong> descanso</li><li>A criação é a base da teologia bíblica sobre a soberania de Deus</li><li>O homem foi criado <span class='destaque-amarelo'>'à imagem de Deus'</span> (<span class='versiculo'>Gn 1:26-27</span>), fundamentando a dignidade humana</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 1:1-2:3</span>"
},
{
    termo: "<span class='numero-ordem'>670.</span> <span class='nome-principal'>O dilúvio e a arca de Noé – Gênesis 6-9</span> <span class='subtitulo'>– julgamento e salvação</span>",
    definicao: "<p>Devido à maldade humana, Deus decidiu destruir a terra com um <strong>dilúvio</strong>. Noé, homem justo, construiu uma arca de madeira de gofer (<span class='versiculo'>Gn 6-9</span>).</p><ul><li><strong>Dimensões:</strong> 300 côvados de comprimento, 50 de largura e 30 de altura (c. 137 x 23 x 14 m)</li><li><strong>Ocupantes:</strong> Noé, sua esposa, três filhos (Sem, Cam, Jafé) e suas esposas, além de pares de todos os animais</li><li><strong>Duração:</strong> choveu 40 dias e 40 noites; as águas prevaleceram 150 dias</li><li>A arca pousou sobre as montanhas de Ararate</li><li>Deus fez uma aliança com Noé e colocou o arco-íris como sinal</li><li><strong>Tipologia:</strong> o dilúvio é um tipo do batismo (<span class='versiculo'>1Pe 3:20-21</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 6:1-9:17; Mt 24:37-39; 1Pe 3:20-21</span>"
},
{
    termo: "<span class='numero-ordem'>671.</span> <span class='nome-principal'>A confusão das línguas em Babel – Gênesis 11:1-9</span> <span class='subtitulo'>– origem da diversidade linguística</span>",
    definicao: "<p>A humanidade, falando uma só língua, decidiu construir uma cidade e uma <strong>torre que chegasse ao céu</strong>, em Sinear (Babilônia) (<span class='versiculo'>Gn 11:1-9</span>).</p><ul><li>Deus confundiu sua língua, e eles pararam a construção</li><li>A cidade chamou-se Babel (confusão)</li><li>Este evento originou a diversidade de línguas e a dispersão dos povos</li><li>A torre de Babel simboliza o orgulho humano e a tentativa de alcançar Deus sem obediência</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 11:1-9</span>"
},
{
    termo: "<span class='numero-ordem'>672.</span> <span class='nome-principal'>A aliança de Deus com Abraão – Gênesis 12; 15; 17</span> <span class='subtitulo'>– a promessa incondicional</span>",
    definicao: "<p>Deus chamou Abrão (depois Abraão) para sair de sua terra, prometendo: <span class='destaque-amarelo'>1) uma grande nação; 2) bênção para todas as famílias da terra; 3) terra de Canaã</span> (<span class='versiculo'>Gn 12:1-3</span>).</p><ul><li>Em <span class='versiculo'>Gn 15</span>, Deus fez um pacto solene, passando entre pedaços de animais</li><li>Em <span class='versiculo'>Gn 17</span>, estabeleceu a circuncisão como sinal da aliança</li><li>Esta aliança é incondicional e messiânica (<span class='versiculo'>Gl 3:16</span>)</li><li>Abraão creu, e isso lhe foi imputado como justiça (<span class='versiculo'>Gn 15:6</span>; <span class='versiculo'>Rm 4:3</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 12:1-3; Gn 15:1-21; Gn 17:1-27; Rm 4:1-25; Gl 3:6-29</span>"
},
{
    termo: "<span class='numero-ordem'>673.</span> <span class='nome-principal'>A travessia do Mar Vermelho – Êxodo 14</span> <span class='subtitulo'>– o grande ato de redenção do AT</span>",
    definicao: "<p>Após as dez pragas, Faraó libertou Israel, mas depois perseguiu o povo. Moisés estendeu sua vara sobre o <strong>Mar Vermelho</strong>, e Deus abriu um caminho seco (<span class='versiculo'>Êx 14:1-31</span>).</p><ul><li>Os israelitas atravessaram, e as águas voltaram sobre o exército egípcio</li><li>Este é o grande ato de redenção do AT</li><li>Tipifica o batismo (<span class='versiculo'>1Co 10:1-2</span>) e a libertação do pecado</li><li>O local exato é debatido (Mar dos Juncos – Yam Suf)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Êx 14:1-31; Sl 106:9; 1Co 10:1-2</span>"
},
{
    termo: "<span class='numero-ordem'>674.</span> <span class='nome-principal'>A entrega da Lei no Sinai – Êxodo 19-20</span> <span class='subtitulo'>– os Dez Mandamentos</span>",
    definicao: "<p>Três meses após o Êxodo, Israel acampou diante do <strong>monte Sinai</strong>. Deus desceu em fogo, trovões, nuvem e trombeta (<span class='versiculo'>Êx 19:1-20:21</span>).</p><ul><li>Moisés subiu ao monte e recebeu os <strong>Dez Mandamentos</strong> (<span class='versiculo'>Êx 20:1-17</span>)</li><li>Escritos em duas tábuas de pedra</li><li>A Lei foi dada para revelar o pecado e servir de tutor até Cristo (<span class='versiculo'>Gl 3:24</span>)</li><li>Apenas Moisés pôde subir ao monte; o povo ficou ao pé, aterrorizado</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Êx 19:1-20:21; Dt 5:1-22; Gl 3:19-25</span>"
},
{
    termo: "<span class='numero-ordem'>675.</span> <span class='nome-principal'>O bezerro de ouro – Êxodo 32</span> <span class='subtitulo'>– a idolatria no Sinai</span>",
    definicao: "<p>Enquanto Moisés estava no Sinai, o povo pediu a Arão que fizesse um deus. Arão fundiu o ouro e fez um <strong>bezerro de ouro</strong> (<span class='versiculo'>Êx 32:1-35</span>).</p><ul><li>O povo disse: 'Eis aqui teus deuses, ó Israel, que te tiraram do Egito'</li><li>Moisés, ao descer, quebrou as tábuas, queimou o bezerro e ordenou aos levitas que matassem os idólatras (c. 3.000 homens)</li><li>Deus ameaçou destruir o povo, mas Moisés intercedeu</li><li>Este episódio ocorreu apenas 40 dias após a entrega da Lei</li><li>Mostra a propensão humana à idolatria</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Êx 32:1-35; Dt 9:7-21</span>"
},
{
    termo: "<span class='numero-ordem'>676.</span> <span class='nome-principal'>A queda de Jericó – Josué 6</span> <span class='subtitulo'>– a conquista milagrosa de Canaã</span>",
    definicao: "<p>Josué, obedecendo a Deus, fez o povo marchar ao redor de Jericó uma vez por dia durante seis dias. No sétimo dia, marcharam sete vezes, os sacerdotes tocaram as trombetas, e o povo gritou. As <strong>muralhas caíram</strong> (<span class='versiculo'>Js 6:1-27</span>).</p><ul><li>Israel conquistou a cidade, poupando Raabe e sua família</li><li>A derrubada das muralhas foi milagrosa, não por efeito acústico, mas por intervenção divina (<span class='versiculo'>Hb 11:30</span>)</li><li>Jericó é a primeira conquista de Israel em Canaã</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Js 6:1-27; Hb 11:30</span>"
},
{
    termo: "<span class='numero-ordem'>677.</span> <span class='nome-principal'>A oração de Elias no Monte Carmelo – 1Rs 18:16-40</span> <span class='subtitulo'>– o confronto com os profetas de Baal</span>",
    definicao: "<p>Elias desafiou <strong>450 profetas de Baal</strong> e 400 de Aserá no Monte Carmelo (<span class='versiculo'>1Rs 18:16-40</span>).</p><ul><li>Cada lado preparou um novilho sobre o altar, invocando seu deus</li><li>Os profetas de Baal clamaram sem resposta</li><li>Elias restaurou o altar de Deus, colocou água ao redor e orou</li><li><span class='destaque-amarelo'>Fogo desceu do céu</span> e consumiu o holocausto, a madeira, as pedras e a água</li><li>O povo se prostrou e matou os profetas de Baal</li><li>Elias usou doze pedras para representar as doze tribos</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 18:16-40</span>"
},
{
    termo: "<span class='numero-ordem'>678.</span> <span class='nome-principal'>A ressurreição de Lázaro – João 11</span> <span class='subtitulo'>– o maior sinal antes da paixão</span>",
    definicao: "<p>Lázaro, irmão de Marta e Maria, morreu em Betânia. Jesus esperou quatro dias antes de ir ao sepulcro (<span class='versiculo'>Jo 11:1-57</span>).</p><ul><li>Mandou remover a pedra, orou e disse: <span class='destaque-amarelo'>'Lázaro, vem para fora'</span></li><li>O morto saiu envolto em faixas</li><li>Este milagre foi o maior sinal antes da paixão</li><li>Levou os líderes judeus a decidirem matar Jesus (<span class='versiculo'>Jo 11:53</span>)</li><li>Foi a última grande obra pública de Jesus, demonstrando seu poder sobre a morte</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jo 11:1-57</span>"
},
{
    termo: "<span class='numero-ordem'>679.</span> <span class='nome-principal'>O Pentecostes – Atos 2</span> <span class='subtitulo'>– o nascimento da igreja</span>",
    definicao: "<p>Cinquenta dias após a Páscoa, os discípulos estavam reunidos em Jerusalém. Veio do céu um som como de um vento impetuoso, <span class='destaque-amarelo'>línguas como de fogo</span> pousaram sobre eles, e começaram a falar em outras línguas (<span class='versiculo'>At 2:1-41</span>).</p><ul><li>Pedro pregou, e cerca de 3.000 pessoas se converteram</li><li>Este evento marca o nascimento da igreja</li><li>É o cumprimento da profecia de Joel (<span class='versiculo'>Jl 2:28-32</span>)</li><li>As línguas de fogo representavam o Espírito Santo (<span class='versiculo'>Mt 3:11</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 2:1-41; Jl 2:28-32</span>"
},
{
    termo: "<span class='numero-ordem'>680.</span> <span class='nome-principal'>A conversão de Saulo no caminho de Damasco – Atos 9</span> <span class='subtitulo'>– o perseguidor que se tornou apóstolo</span>",
    definicao: "<p>Saulo (Paulo), perseguidor da igreja, a caminho de Damasco para prender cristãos, foi cercado por uma <span class='destaque-amarelo'>luz do céu</span>. Ouviu a voz de Jesus: <span class='destaque-amarelo'>'Saulo, Saulo, por que me persegues?'</span> (<span class='versiculo'>At 9:1-19</span>).</p><ul><li>Ficou cego por três dias</li><li>Ananias o batizou, e ele recuperou a visão</li><li>Tornou-se o apóstolo dos gentios</li><li>Este é um dos eventos mais transformadores da história do cristianismo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 9:1-19; At 22:1-16; At 26:9-18</span>"
},
{
    termo: "<span class='numero-ordem'>681.</span> <span class='nome-principal'>A visão de Pedro em Jope – Atos 10:9-16</span> <span class='subtitulo'>– a quebra das barreiras alimentares e raciais</span>",
    definicao: "<p>Pedro orando sobre o terraço, em Jope, teve uma visão: um <strong>lençol descendo do céu</strong> com animais impuros. Uma voz disse: 'Levanta-te, mata e come'. Pedro recusou. A voz respondeu: <span class='destaque-amarelo'>'Não chames impuro o que Deus purificou'</span> (<span class='versiculo'>At 10:9-16</span>).</p><ul><li>Isso aconteceu três vezes</li><li>A visão preparou Pedro para pregar a Cornélio</li><li>Foi um marco para a abertura do evangelho aos gentios</li><li>Quebrou as barreiras alimentares e raciais</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 10:9-16; At 11:4-10</span>"
},
{
    termo: "<span class='numero-ordem'>682.</span> <span class='nome-principal'>O terremoto na prisão de Filipos – Atos 16:25-34</span> <span class='subtitulo'>– o poder do louvor em meio ao sofrimento</span>",
    definicao: "<p>Paulo e Silas, presos em Filipos, oravam e cantavam louvores à meia-noite. Um <strong>terremoto</strong> abriu as portas e soltou as cadeias (<span class='versiculo'>At 16:25-34</span>).</p><ul><li>O carcereiro, pensando que os presos haviam fugido, ia matar-se</li><li>Paulo gritou: 'Não te faças nenhum mal, pois todos aqui estamos'</li><li>O carcereiro perguntou: 'Senhores, que devo fazer para me salvar?'</li><li>Eles responderam: <span class='destaque-amarelo'>'Crê no Senhor Jesus e serás salvo, tu e tua casa'</span></li><li>Foi batizado com sua família</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 16:25-34</span>"
},
{
    termo: "<span class='numero-ordem'>683.</span> <span class='nome-principal'>O concílio de Jerusalém – Atos 15</span> <span class='subtitulo'>– o primeiro concílio da história da igreja</span>",
    definicao: "<p>Conflito sobre a necessidade da circuncisão para os gentios convertidos. Paulo e Barnabé foram a Jerusalém. <strong>Pedro, Tiago e outros líderes</strong> decidiram que os gentios não precisavam se submeter à Lei de Moisés (<span class='versiculo'>At 15:1-35</span>).</p><ul><li>Apenas deveriam abster-se de ídolos, sangue, carnes sufocadas e imoralidade sexual</li><li>Esta decisão libertou a igreja do legalismo judaico</li><li>Foi o primeiro concílio da história da igreja</li><li>Uniu judeus e gentios</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 15:1-35; Gl 2:1-10</span>"
},
{
    termo: "<span class='numero-ordem'>684.</span> <span class='nome-principal'>O naufrágio de Paulo – Atos 27</span> <span class='subtitulo'>– um dos relatos mais detalhados sobre navegação antiga</span>",
    definicao: "<p>Paulo, preso, foi enviado a Roma em um navio que enfrentou uma tempestade. Após 14 dias à deriva, o navio <strong>naufragou na ilha de Malta</strong> (<span class='versiculo'>At 27:1-28:10</span>).</p><ul><li>Todos os 276 passageiros se salvaram, conforme Paulo profetizara</li><li>Em Malta, Paulo foi picado por uma víbora, mas não sofreu mal</li><li>Curou o pai de Públio</li><li>Este relato é um dos mais detalhados sobre navegação antiga</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 27:1-28:10</span>"
},
{
    termo: "<span class='numero-ordem'>685.</span> <span class='nome-principal'>A morte de Herodes Agripa I – Atos 12:20-23</span> <span class='subtitulo'>– o julgamento divino contra o perseguidor</span>",
    definicao: "<p>Herodes Agripa I, perseguidor da igreja, vestiu vestes reais e fez um discurso diante do povo de Tiro e Sidom. O povo gritou: <span class='destaque-vermelho'>'Voz de um deus, não de homem!'</span> (<span class='versiculo'>At 12:20-23</span>).</p><ul><li>Um anjo do Senhor o feriu, e ele morreu comido por vermes</li><li>Este julgamento divino contrasta com a libertação de Pedro</li><li>A descrição de sua morte é corroborada pelo historiador Josefo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 12:20-23</span>"
},
{
    termo: "<span class='numero-ordem'>686.</span> <span class='nome-principal'>O jejum de 40 dias de Jesus no deserto – Mt 4:1-11</span> <span class='subtitulo'>– a tentação e a resistência com as Escrituras</span>",
    definicao: "<p>Após ser batizado, Jesus foi levado pelo Espírito ao deserto para ser tentado por Satanás. Jejuou <strong>40 dias e 40 noites</strong> (<span class='versiculo'>Mt 4:1-11</span>).</p><ul><li>O diabo tentou transformar pedras em pão, lançar-se do pináculo do templo e adorá-lo</li><li>Jesus resistiu com as Escrituras (<span class='versiculo'>Dt 8:3</span>; <span class='versiculo'>6:16</span>; <span class='versiculo'>6:13</span>)</li><li>Este período relembra os 40 anos de Israel no deserto</li><li>Jesus venceu a tentação onde Israel havia falhado</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 4:1-11; Mc 1:12-13; Lc 4:1-13</span>"
},
{
    termo: "<span class='numero-ordem'>687.</span> <span class='nome-principal'>A transfiguração de Jesus – Mt 17:1-8</span> <span class='subtitulo'>– a confirmação da divindade de Jesus</span>",
    definicao: "<p>Jesus levou Pedro, Tiago e João a um monte alto. Foi <strong>transfigurado</strong> diante deles: seu rosto brilhou como o sol, e suas vestes se tornaram brancas como a luz (<span class='versiculo'>Mt 17:1-8</span>).</p><ul><li>Apareceram Moisés e Elias conversando com Jesus</li><li>Uma nuvem os cobriu e uma voz disse: <span class='destaque-amarelo'>'Este é o meu Filho amado, em quem me comprazo; ouvi-o'</span></li><li>Este evento confirmou a divindade de Jesus</li><li>Mostrou sua superioridade sobre Moisés (a Lei) e Elias (os Profetas)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 17:1-8; Mc 9:2-8; Lc 9:28-36</span>"
},
{
    termo: "<span class='numero-ordem'>688.</span> <span class='nome-principal'>A ascensão de Jesus ao céu – Atos 1:9-11</span> <span class='subtitulo'>– o fim do ministério terreno de Cristo</span>",
    definicao: "<p>Quarenta dias após a ressurreição, Jesus reuniu os apóstolos no Monte das Oliveiras. Enquanto os abençoava, foi <strong>elevado às alturas</strong>, e uma nuvem o recebeu (<span class='versiculo'>At 1:9-11</span>).</p><ul><li>Dois anjos apareceram e disseram: <span class='destaque-amarelo'>'Esse Jesus que dentre vós foi elevado ao céu, assim virá do modo como o vistes ir para o céu'</span></li><li>A ascensão marca o fim do ministério terreno de Cristo</li><li>É o início de sua intercessão celestial</li><li>A ascensão é celebrada 40 dias após a Páscoa</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 24:50-53; At 1:9-11; Ef 4:8-10</span>"
},
{
    termo: "<span class='numero-ordem'>689.</span> <span class='nome-principal'>Os 70 (72) discípulos enviados por Jesus – Lc 10:1-24</span> <span class='subtitulo'>– a missão da igreja</span>",
    definicao: "<p>Jesus enviou <strong>70 (ou 72) discípulos</strong>, dois a dois, para pregar, curar e anunciar a chegada do reino (<span class='versiculo'>Lc 10:1-24</span>).</p><ul><li>Voltaram alegres, dizendo que até os demônios se submetiam em nome de Jesus</li><li>Esses discípulos são anônimos</li><li>A tradição dá nomes a alguns (como Lucas, Cleopas, etc.)</li><li>Representam a missão da igreja e a autoridade dada por Cristo</li><li>Os 70 correspondem às nações listadas em Gênesis 10 ou ao número dos anciãos de Israel (<span class='versiculo'>Nm 11:16</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 10:1-24</span>"
},
{
    termo: "<span class='numero-ordem'>690.</span> <span class='nome-principal'>O anjo do Senhor (teofania)</span> <span class='subtitulo'>– manifestação de Deus no AT</span>",
    definicao: "<p>O <strong>Anjo do Senhor</strong> é uma figura especial no AT que fala como Deus, recebe adoração e é chamado de Senhor.</p><ul><li>Exemplos: Hagar (<span class='versiculo'>Gn 16</span>), Abraão (<span class='versiculo'>Gn 22</span>), Moisés (sarça ardente), Gideão (<span class='versiculo'>Jz 6</span>), Sansão (<span class='versiculo'>Jz 13</span>)</li><li>Muitos teólogos veem nessa figura uma manifestação pré-encarnada de Cristo</li><li>No NT, o anjo do Senhor não aparece mais</li><li>É uma evidência da Trindade no AT</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 16:7-14; Gn 22:11-18; Êx 3:2-6; Jz 6:11-24; Jz 13:3-22; Js 5:13-15</span>"
},
{
    termo: "<span class='numero-ordem'>691.</span> <span class='nome-principal'>Os anjos que anunciaram a ressurreição – Mt 28; Mc 16; Lc 24; Jo 20</span> <span class='subtitulo'>– mensageiros da boa nova</span>",
    definicao: "<p>Os <strong>anjos</strong> anunciaram a ressurreição de Jesus às mulheres que foram ao sepulcro.</p><ul><li>Em Mateus 28:5-7, um anjo disse: 'Não temais; sei que buscais a Jesus crucificado. Não está aqui; ressuscitou!'</li><li>Em Marcos 16:5-7, um jovem vestido de branco anunciou a ressurreição</li><li>Em Lucas 24:4-7, dois homens com vestes resplandecentes</li><li>Em João 20:12-13, dois anjos sentados no sepulcro</li><li>Os anjos são mensageiros da maior notícia da história</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 28:5-7; Mc 16:5-7; Lc 24:4-7; Jo 20:12-13</span>"
},
{
    termo: "<span class='numero-ordem'>692.</span> <span class='nome-principal'>A Tabela das Nações – Gn 10</span> <span class='subtitulo'>– a origem dos povos</span>",
    definicao: "<p>A <strong>Tabela das Nações</strong> em <span class='versiculo'>Gn 10</span> é fundamental para a etnografia bíblica. Ela lista os descendentes de Noé e a origem das nações conhecidas por Israel.</p><ul><li><strong>Sem:</strong> Elão, Assur, Arfaxade, Lud, Arã (povos do Oriente Médio)</li><li><strong>Jafé:</strong> Gomer, Magogue, Madai, Javã, Tubal, Meseque, Tiras (povos indo-europeus)</li><li><strong>Cam:</strong> Cuxe, Mizraim, Pute, Canaã (povos da África e Canaã)</li><li>Mostra a unidade da humanidade e a dispersão dos povos</li><li>É uma ponte entre a história primordial e a chamada de Abraão</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 10:1-32; 1Cr 1:1-23</span>"
},
{
    termo: "<span class='numero-ordem'>693.</span> <span class='nome-principal'>Penina</span> <span class='subtitulo'>– a rival de Ana, esposa de Elcana, que a provocava por sua esterilidade</span>",
    definicao: "<p><strong>Penina</strong> foi uma das duas esposas de Elcana, o levita de Ramá, pai do profeta Samuel (<span class='versiculo'>1Sm 1:2</span>). Enquanto Ana era estéril, Penina tinha filhos e, por isso, a provocava constantemente, aumentando sua amargura.</p><ul><li><strong>Nome:</strong> significa 'pérola' ou 'coral'</li><li>Penina é mencionada apenas em 1Samuel 1-2</li><li>Ela representa a rivalidade familiar e a dor da infertilidade</li><li>Apesar de sua atitude provocadora, Penina cumpriu o papel de dar filhos a Elcana</li><li>Ana, mesmo provocada, perseverou em oração e foi ouvida por Deus</li><li>A história de Penina nos lembra que a verdadeira dignidade não vem da fertilidade, mas da fé</li><li>Penina não é mencionada no NT</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 1:2,4-7; 1Sm 2:21</span>"
},
{
    termo: "<span class='numero-ordem'>694.</span> <span class='nome-principal'>Maer-Salal-Hás-Baz</span> <span class='subtitulo'>– o segundo filho simbólico do profeta Isaías, cujo nome profetizava a queda de Damasco e Samaria</span>",
    definicao: "<p><strong>Maer-Salal-Hás-Baz</strong> foi o segundo filho do profeta Isaías com a profetisa (sua esposa), mencionado em <span class='versiculo'>Is 8:3</span>. Seu nome significa <span class='destaque-amarelo'>'Rápido-Despojo, Presa-Saque'</span>.</p><ul><li>Deus ordenou que Isaías desse esse nome ao filho como um sinal profético</li><li>O nome indicava que, antes que o menino aprendesse a dizer 'pai' e 'mãe', a riqueza de Damasco e o despojo de Samaria seriam levados pelo rei da Assíria (<span class='versiculo'>Is 8:4</span>)</li><li>Este foi um dos nomes simbólicos usados por Isaías para transmitir mensagens divinas</li><li>Maer-Salal-Hás-Baz é um exemplo de como os profetas usavam seus próprios filhos como sinais vivos</li><li>O nome cumpre a profecia contra a Síria e Israel (Rezim e Peca)</li><li>No NT, não é citado</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Is 8:1-4</span>"
},
{
    termo: "<span class='numero-ordem'>695.</span> <span class='nome-principal'>Sear-Jasube</span> <span class='subtitulo'>– o primeiro filho simbólico de Isaías, cujo nome significava 'um remanescente voltará'</span>",
    definicao: "<p><strong>Sear-Jasube</strong> foi o primeiro filho do profeta Isaías, mencionado em <span class='versiculo'>Is 7:3</span>. Seu nome significa <span class='destaque-amarelo'>'Um remanescente voltará'</span> ou 'O restante retornará'.</p><ul><li>Deus ordenou que Isaías levasse Sear-Jasube ao encontro do rei Acaz durante a crise com a Síria e Israel (<span class='versiculo'>Is 7:3</span>)</li><li>O nome transmitia uma mensagem de esperança: apesar do juízo iminente, Deus preservaria um remanescente fiel</li><li>Isso se cumpriu quando Judá foi exilado na Babilônia e depois um remanescente retornou</li><li>Sear-Jasube é um exemplo de profecia viva através de nomes</li><li>O remanescente é um tema central nos profetas (Isaías, Jeremias, Miqueias)</li><li>No NT, Paulo retoma o tema do remanescente (<span class='versiculo'>Rm 9:27</span>; <span class='versiculo'>Rm 11:5</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Is 7:3; Is 10:20-22; Rm 9:27</span>"
},
{
    termo: "<span class='numero-ordem'>696.</span> <span class='nome-principal'>Urias (profeta)</span> <span class='subtitulo'>– filho de Semaías, morto por Jeoaquim por profetizar contra Judá (Jr 26:20-23)</span>",
    definicao: "<p><strong>Urias</strong>, filho de Semaías, foi um profeta da cidade de Quiriate-Jearim que profetizou contra Judá e Jerusalém durante o reinado de Jeoaquim, com palavras semelhantes às de Jeremias (<span class='versiculo'>Jr 26:20-23</span>).</p><ul><li>Quando o rei Jeoaquim ouviu suas palavras, mandou matá-lo</li><li>Urias fugiu para o Egito, mas foi extraditado e executado à espada, e seu corpo foi lançado em covas comuns</li><li>Este é um dos exemplos de perseguição profética no AT</li><li>Diferentemente de Jeremias, que foi protegido, Urias não teve a mesma sorte</li><li>Urias significa 'Yahweh é minha luz'</li><li>Sua morte mostra o perigo de profetizar contra a vontade do rei</li><li>No NT, não é citado</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jr 26:20-23</span>"
},
{
    termo: "<span class='numero-ordem'>697.</span> <span class='nome-principal'>Evil-Merodaque</span> <span class='subtitulo'>– rei da Babilônia que libertou Joaquim (Jeconias) da prisão</span>",
    definicao: "<p><strong>Evil-Merodaque</strong> foi rei da Babilônia (562-560 a.C.), filho e sucessor de Nabucodonosor. Em seu primeiro ano de reinado, libertou Joaquim (Jeconias), rei de Judá, da prisão, tratou-o com bondade e lhe deu lugar de honra entre os reis cativos (<span class='versiculo'>2Rs 25:27-30</span>; <span class='versiculo'>Jr 52:31-34</span>).</p><ul><li>Este gesto de bondade ocorreu 37 anos após Joaquim ser levado cativo (597 a.C.)</li><li>Evil-Merodaque significa 'homem de Marduque' (deus babilônico)</li><li>Ele inverteu a sentença de seu pai, mostrando que a misericórdia pode vir mesmo de reis pagãos</li><li>Joaquim recebeu roupas novas e uma mesa à parte, e recebeu subsídio diário até sua morte</li><li>Este evento é um sinal de esperança para o povo exilado</li><li>No NT, não é citado</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Rs 25:27-30; Jr 52:31-34</span>"
},
{
    termo: "<span class='numero-ordem'>698.</span> <span class='nome-principal'>A esposa de Jeroboão I (anônima)</span> <span class='subtitulo'>– que se disfarçou para consultar o profeta Aías sobre a doença de seu filho (1Rs 14:1-18)</span>",
    definicao: "<p>A <strong>esposa de Jeroboão I</strong> (cujo nome não é dado) foi enviada pelo rei a Siló para consultar o profeta Aías sobre a doença de seu filho Abia (<span class='versiculo'>1Rs 14:1-18</span>).</p><ul><li>Jeroboão ordenou que ela se disfarçasse para que Aías não a reconhecesse</li><li>No entanto, Aías, já cego pela velhice, foi avisado por Deus e a identificou imediatamente</li><li>Ele profetizou a morte do menino e a destruição da casa de Jeroboão</li><li>A esposa voltou e, ao pisar em casa, o menino morreu</li><li>Ela é um exemplo de como a hipocrisia não pode enganar a Deus</li><li>A profecia de Aías foi cumprida integralmente</li><li>Seu nome não é registrado, mas seu papel é crucial na narrativa</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 14:1-18</span>"
},
{
    termo: "<span class='numero-ordem'>699.</span> <span class='nome-principal'>Is-Bosete (Esh-Baal)</span> <span class='subtitulo'>– filho de Saul, que reinou sobre Israel por dois anos, rival de Davi</span>",
    definicao: "<p><strong>Is-Bosete</strong> (também chamado <strong>Esh-Baal</strong> em <span class='versiculo'>1Cr 8:33</span>; <span class='versiculo'>9:39</span>) foi o quarto filho de Saul e sucessor de seu pai como rei sobre o reino do norte, com exceção de Judá, que seguiu Davi (<span class='versiculo'>2Sm 2:8-10</span>).</p><ul><li>Seu nome significa 'homem de vergonha' (uma substituição de 'Baal' por 'Bosete' – vergonha)</li><li>Reinou por dois anos em Maanaim, sob a tutela do comandante Abner</li><li>Abner, após um desentendimento, transferiu seu apoio a Davi</li><li>Is-Bosete foi assassinado por dois de seus capitães, Baaná e Recabe, enquanto dormia (<span class='versiculo'>2Sm 4:5-7</span>)</li><li>Davi executou os assassinos e honrou Is-Bosete com um sepultamento digno</li><li>Is-Bosete representa a resistência à unificação de Israel sob Davi</li><li>No NT, não é citado</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 2:8-10; 2Sm 3:6-11; 2Sm 4:1-12; 1Cr 8:33; 1Cr 9:39</span>"
},
{
    termo: "<span class='numero-ordem'>700.</span> <span class='nome-principal'>Abia (filho de Samuel)</span> <span class='subtitulo'>– filho de Samuel, juiz corrupto em Berseba, rejeitado pelo povo (1Sm 8:2-5)</span>",
    definicao: "<p><strong>Abia</strong> foi um dos filhos do profeta Samuel, que ele constituiu como juiz em Berseba (<span class='versiculo'>1Sm 8:2</span>). Juntamente com seu irmão Joel, Abia corrompeu-se, aceitando subornos e pervertendo a justiça.</p><ul><li>O povo, insatisfeito com a corrupção dos filhos de Samuel, pediu um rei para julgar Israel (<span class='versiculo'>1Sm 8:4-5</span>)</li><li>Este pedido desagradou a Samuel, mas Deus o orientou a atender ao povo, embora isso significasse rejeição a Ele</li><li>Abia significa 'Yahweh é meu pai'</li><li>A corrupção dos filhos de Samuel foi o principal motivo para a instauração da monarquia</li><li>Abia e Joel representam a falha da liderança hereditária e a necessidade de reforma</li><li>No NT, não é citado</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 8:2-5; 1Sm 12:2-5</span>"
    }
]
};
